e\n103:   public Optional\u003cString\u003e identifier(CdsIndexTrade target) {\n104:     return target.getInfo().getId().map(id -\u003e id.toString());\n105:   }\n106: \n107:   @Override\n108:   public Currency naturalCurrency(CdsIndexTrade trade, ReferenceData refData) {\n109:     return trade.getProduct().getCurrency();\n110:   }\n111: \n112:   //-------------------------------------------------------------------------\n113:   @Override\n114:   public FunctionRequirements requirements(\n115:       CdsIndexTrade trade,\n116:       Set\u003cMeasure\u003e measures,\n117:       CalculationParameters parameters,\n118:       ReferenceData refData) {\n119: \n120:     // extract data from product\n121:     CdsIndex product = trade.getProduct();\n122:     StandardId legalEntityId = product.getCdsIndexId();\n123:     Currency currency = product.getCurrency();\n124: \n125:     // use lookup to build requirements\n126:     CreditRatesMarketDataLookup lookup = parameters.getParameter(CreditRatesMarketDataLookup.class);\n127:     return lookup.requirements(legalEntityId, currency);\n128:   }\n129: \n130:   //-------------------------------------------------------------------------\n131:   @Override\n132:   public Map\u003cMeasure, Result\u003c?\u003e\u003e calculate(\n133:       CdsIndexTrade trade,\n134:       Set\u003cMeasure\u003e measures,\n135:       CalculationParameters parameters,\n136:       ScenarioMarketData scenarioMarketData,\n137:       ReferenceData refData) {\n138: \n139:     // resolve the trade once for all measures and all scenarios\n140:     ResolvedCdsIndexTrade resolved = trade.resolve(refData);\n141: \n142:     // use lookup to query market data\n143:     CreditRatesMarketDataLookup ledLookup = parameters.getParameter(CreditRatesMarketDataLookup.class);\n144:     CreditRatesScenarioMarketData marketData = ledLookup.marketDataView(scenarioMarketData);\n145: \n146:     // loop around measures, calculating all scenarios for one measure\n147:     Map\u003cMea