import com.opengamma.strata.basics.schedule.PeriodicSchedule;
import com.opengamma.strata.basics.schedule.RollConventions;
import com.opengamma.strata.basics.schedule.Schedule;
import com.opengamma.strata.basics.schedule.SchedulePeriod;
import com.opengamma.strata.basics.schedule.StubConvention;
import com.opengamma.strata.collect.ArgChecker;
import com.opengamma.strata.product.Product;
import com.opengamma.strata.product.common.BuySell;

/**
 * A CDS index tranche product.
 * <p>
 * A CDS tranche is a slice of credit risk from a CDS index portfolio, defined by
 * attachment and detachment points that determine the subordination level.
 * The protection buyer periodically pays fixed coupons to the protection seller until expiry.
 * In return, the protection buyer receives compensation for portfolio losses within
 * the tranche range [attachmentPoint, detachmentPoint].
 */
@BeanDefinition
public final class CdsTranche
    implements Product, Resolvable<ResolvedCdsTranche>, ImmutableBean, Serializable {

  /**
   * Whether the CDS tranche is buy or sell.
   * <p>
   * A value of 'Buy' implies buying protection, where the fixed coupon is paid
   * and the protection is received in the event of defaults within the tranche.
   * A value of 'Sell' implies selling protection, where the fixed coupon is received
   * and the protection is paid for losses in the tranche.
   */
  @PropertyDefinition(validate = "notNull")
  private final BuySell buySell;
  /**
   * The CDS index identifier underlying this tranche.
   * <p>
   * This identifier refers to the CDS index on which this tranche is based.
   */
  @PropertyDefinition(validate = "notNull")
  private final StandardId cdsIndexId;
  /**
   * The legal entity identifiers.
   * <p>
   * These identifiers refer to the reference legal entities of the underlying CDS index.
   */
  @PropertyDefinition(validate = "notNull")
  private final ImmutableList<StandardId> legalEntityIds;
  /**
   * The attachment point of the tranche.
   * <p>
   * The attachment point defines the lower boundary of the tranche as a fraction
   * of the total portfolio notional (between 0.0 and 1.0).
   * Losses below this level are absorbed by more junior tranches.
   */
  @PropertyDefinition
  private final double attachmentPoint;
  /**
   * The detachment point of the tranche.
   * <p>
   * The detachment point defines the upper boundary of the tranche as a fraction
   * of the total portfolio notional (between 0.0 and 1.0).
   * Losses above this level are absorbed by more senior tranches.
   * Must be greater than the attachment point.
   */
  @PropertyDefinition
  private final double detachmentPoint;
  /**
   * The currency of the CDS tranche.
   * <p>
   * The amounts of the notional are expressed in terms of this currency.
   */
  @PropertyDefinition(validate = "notNull")
  private final Currency currency;
  /**
   * The notional amount, must be non-negative.
   * <p>
   * The fixed notional amount applicable during the lifetime of the tranche.
   * The currency of the notional is specified by {@code currency}.
   */
  @PropertyDefinition(validate = "ArgChecker.notNegativeOrZero")
  private final double notional;
  /**
   * The payment schedule.
   * <p>
   * This is used to define the payment periods.
   */
  @PropertyDefinition(validate = "notNull")
  private final PeriodicSchedule paymentSchedule;
  /**
   * The fixed coupon rate.
   * <p>
   * This must be represented in decimal form.
   */
  @PropertyDefinition(validate = "ArgChecker.notNegative")
  private final double fixedRate;
  /**
   * The day count convention.
   * <p>
   * This is used to convert dates to a numerical value.
   * <p>
   * When building, this will default to 'Act/360'.
   */
  @PropertyDefinition(validate = "notNull")
  private final DayCount dayCount;
  /**
   * The payment on default.
   * <p>
   * Whether the accrued premium is paid in the event of a default.
   * <p>
   * When building, this will default to 'AccruedPremium'.
   */
  @PropertyDefinition(validate = "notNull")
  private final PaymentOnDefault paymentOnDefault;
  /**
   * The protection start of the day.
   * <p>
   * When the protection starts on the start date.
   * <p>
   * When building, this will default to 'Beginning'.
   */
  @PropertyDefinition(validate = "notNull")
  private final ProtectionStartOfDay protectionStart;
  /**
   * The number of days between valuation date and step-in date.
   * <p>
   * The step-in date is also called protection effective date.
   * It is usually 1 calendar day for standardized CDS contracts.
   * <p>
   * When building, this will default to 1 calendar day.
   */
  @PropertyDefinition(validate = "notNull")
  private final DaysAdjustment stepinDateOffset;
  /**
   * The number of days between valuation date and settlement date.
   * <p>
   * It is usually 3 business days for standardized CDS contracts.
   * <p>
   * When building, this will default to 3 business days in the calendar of the payment schedule.
   */
  @PropertyDefinition(validate = "notNull")
  private final DaysAdjustment settlementDateOffset;

  //-------------------------------------------------------------------------
  /**
   * Creates an instance of a standardized CDS tranche.
   *
   * @param buySell  buy or sell
   * @param cdsIndexId  the CDS index ID
   * @param legalEntityIds  the legal entity IDs
   * @param attachmentPoint  the attachment point (0.0 to 1.0)
   * @param detachmentPoint  the detachment point (0.0 to 1.0, greater than attachment)
   * @param currency  the currency
   * @param notional  the notional
   * @param startDate  the start date
   * @param endDate  the end date
   * @param calendar  the calendar
   * @param paymentFrequency  the payment frequency
   * @param fixedRate  the fixed coupon rate
   * @return the instance
   */
  public static CdsTranche of(
      BuySell buySell,
      StandardId cdsIndexId,
      List<StandardId> legalEntityIds,
      double attachmentPoint,
      double detachmentPoint,
      Currency currency,
      double notional,
      LocalDate startDate,
      LocalDate endDate,
