package com.opengamma.strata.pricer.credit;

import java.time.LocalDate;

import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.basics.currency.Payment;
import com.opengamma.strata.collect.ArgChecker;
import com.opengamma.strata.market.sensitivity.PointSensitivities;
import com.opengamma.strata.market.sensitivity.PointSensitivityBuilder;
import com.opengamma.strata.pricer.DiscountingPaymentPricer;
import com.opengamma.strata.pricer.common.PriceType;
import com.opengamma.strata.product.credit.ResolvedCdsTranche;
import com.opengamma.strata.product.credit.ResolvedCdsTrancheTrade;

/**
 * Pricer for CDS index tranche trades based on the ISDA standard model.
 * <p>
 * A CDS tranche represents a slice of credit risk from a CDS index portfolio,
 * defined by attachment and detachment points. This pricer delegates to
 * {@link IsdaCdsTrancheProductPricer} for product-level calculations and adds
 * trade-level adjustments such as upfront fee pricing.
 * <p>
 * The tranche present value is computed by scaling the underlying index's
 * protection and premium legs by the tranche factor (detachmentPoint - attachmentPoint).
 * The protection leg only covers losses within the tranche range.
 */
public class IsdaCdsTranchePricer {

  /**
   * Default implementation.
   */
  public static final IsdaCdsTranchePricer DEFAULT = new IsdaCdsTranchePricer(AccrualOnDefaultFormula.ORIGINAL_ISDA);

  /**
   * The product pricer.
   */
  private final IsdaCdsTrancheProductPricer productPricer;
  /**
   * The upfront fee pricer.
   */
  private final DiscountingPaymentPricer upfrontPricer;

  //-------------------------------------------------------------------------
  /**
   * Creates an instance using the default accrual-on-default formula.
   */
  public IsdaCdsTranchePricer() {
    this.productPricer = IsdaCdsTrancheProductPricer.DEFAULT;
    this.upfrontPricer = DiscountingPaymentPricer.DEFAULT;
  }

  /**
   * Creates an instance specifying the accrual-on-default formula.
   *
   * @param formula  the accrual-on-default formula
   */
  public IsdaCdsTranchePricer(AccrualOnDefaultFormula formula) {
    this.productPricer = new IsdaCdsTrancheProductPricer(formula);
    this.upfrontPricer = DiscountingPaymentPricer.DEFAULT;
  }

  //-------------------------------------------------------------------------
  /**
   * Gets the accrual-on-default formula used in this pricer.
   *
   * @return the formula
   */
  public AccrualOnDefaultFormula getAccrualOnDefaultFormula() {
    return productPricer.getAccrualOnDefaultFormula();
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the price of the tranche trade (present value per unit notional).
   * <p>
   * This method can calculate the clean or dirty price.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the price
   */
  public double price(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      PriceType priceType,
      ReferenceData refData) {

    ResolvedCdsTranche tranche = trade.getProduct();
    LocalDate settlementDate = calculateSettlementDate(trade, ratesProvider, refData);
    return productPricer.price(tranche, ratesProvider, settlementDate, priceType, refData);
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value of the tranche trade.
   * <p>
   * The present value of the product is based on the valuation date.
   * If calculating the clean value, the accrued interest is based on the step-in date.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the present value
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      PriceType priceType,
      ReferenceData refData) {

    ResolvedCdsTranche tranche = trade.getProduct();
    LocalDate settlementDate = calculateSettlementDate(trade, ratesProvider, refData);
    CurrencyAmount pvProduct = productPricer.presentValue(tranche, ratesProvider, settlementDate, priceType, refData);
    if (trade.getUpfrontFee().isPresent()) {
      Payment upfrontFee = trade.getUpfrontFee().get();
      CurrencyAmount pvFee = upfrontPricer.presentValue(upfrontFee, ratesProvider.discountFactors(upfrontFee.getCurrency()));
      return pvProduct.plus(pvFee);
    }
    return pvProduct;
  }

  /**
   * Calculates the present value of the tranche trade on the settlement date.
   * <p>
   * The present value of the trade on the cash settlement date.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param priceType  the price type
   * @param refData  the reference data
   * @return the present value on settlement
   */
  public CurrencyAmount presentValueOnSettle(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      PriceType priceType,
      ReferenceData refData) {

    ResolvedCdsTranche tranche = trade.getProduct();
    LocalDate settlementDate = calculateSettlementDate(trade, ratesProvider, refData);
    return productPricer.presentValue(tranche, ratesProvider, settlementDate, priceType, refData);
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value sensitivity of the tranche trade.
   * <p>
   * The present value sensitivity of the trade is the sensitivity of present value
   * to the underlying curves.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param refData  the reference data
   * @return the present value sensitivity
   */
  public PointSensitivities presentValueSensitivity(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    ResolvedCdsTranche tranche = trade.getProduct();
    LocalDate settlementDate = calculateSettlementDate(trade, ratesProvider, refData);
    PointSensitivityBuilder pvSensiProduct =
        productPricer.presentValueSensitivity(tranche, ratesProvider, settlementDate, refData);
    if (trade.getUpfrontFee().isPresent()) {
      Payment upfrontFee = trade.getUpfrontFee().get();
      PointSensitivityBuilder pvSensiFee =
          upfrontPricer.presentValueSensitivity(upfrontFee, ratesProvider.discountFactors(upfrontFee.getCurrency()));
      return pvSensiProduct.combinedWith(pvSensiFee).build();
    }
    return pvSensiProduct.build();
  }

  /**
   * Calculates the present value sensitivity of the tranche trade on settlement.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param refData  the reference data
   * @return the present value on settlement sensitivity
   */
  public PointSensitivities presentValueOnSettleSensitivity(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    ResolvedCdsTranche tranche = trade.getProduct();
    LocalDate settlementDate = calculateSettlementDate(trade, ratesProvider, refData);
    return productPricer.presentValueSensitivity(tranche, ratesProvider, settlementDate, refData).build();
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the par spread of the tranche trade.
   * <p>
   * The par spread is the coupon rate that makes the clean PV equal to zero.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @param refData  the reference data
   * @return the par spread
   */
  public double parSpread(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    ResolvedCdsTranche tranche = trade.getProduct();
    LocalDate settlementDate = calculateSettlementDate(trade, ratesProvider, refData);
    return productPricer.parSpread(tranche, ratesProvider, settlementDate, refData);
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the expected loss of the tranche.
   * <p>
   * The expected loss represents the expected credit loss for the tranche,
   * computed as the expected portfolio loss that falls within the tranche boundaries.
   *
   * @param trade  the trade
   * @param ratesProvider  the rates provider
   * @return the expected loss
   */
  public CurrencyAmount expectedLoss(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider) {

    return productPricer.expectedLoss(trade.getProduct(), ratesProvider);
  }

  //-------------------------------------------------------------------------
  // calculate the settlement date
  private LocalDate calculateSettlementDate(
      ResolvedCdsTrancheTrade trade,
      CreditRatesProvider ratesProvider,
      ReferenceData refData) {

    return trade.getProduct().calculateSettlementDateFromValuation(ratesProvider.getValuationDate(), refData);
  }

