 * <p>
 * A CDS tranche represents a slice of credit risk from a CDS index portfolio.
 * The tranche is defined by attachment and detachment points that determine
 * the range of portfolio losses covered by this tranche.
 * <p>
 * This pricer delegates to {@link IsdaCdsProductPricer} for the underlying
 * single-name CDS calculations, then applies tranche-specific adjustments.
 * The tranche protection leg covers only losses between the attachment and
 * detachment points as a fraction of the total portfolio notional.
 * <p>
 * The key pricing formula:
 * <ul>
 *   <li>Protection leg: (1 - recoveryRate) * trancheWidth * underlying protection schedule
 *   <li>Premium leg: trancheWidth * underlying risky annuity * fixedRate
 *   <li>PV = buyerSign * notional * (protectionLeg - premiumLeg)
 * </ul>
 * where trancheWidth = detachmentPoint - attachmentPoint.
 */
public class IsdaCdsTrancheProductPricer {

  /**
   * Default implementation.
   */
  public static final IsdaCdsTrancheProductPricer DEFAULT =
      new IsdaCdsTrancheProductPricer(AccrualOnDefaultFormula.ORIGINAL_ISDA);

  /**
   * The pricer for single name CDS, used to compute the underlying schedule.
   */
  private final IsdaCdsProductPricer underlyingPricer;

  /**
   * Creates an instance specifying the formula to use for accrued on default.
   *
   * @param formula  the formula
   */
  public IsdaCdsTrancheProductPricer(AccrualOnDefaultFormula formula) {
    this.underlyingPricer = new IsdaCdsProductPricer(ArgChecker.notNull(formula, "formula"));
  }

  //-------------------------------------------------------------------------
  /**
   * Gets the accrual-on-default formula used in this pricer.
   *
   * @return the formula
   */
  public AccrualOnDefaultFormula getAccrualOnDefaultFormula() {
    return underlyingPricer.getAccrualOnDefaultFormula();
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the price of the tranche product (PV per unit notional).
   * <p>
   * The price is the present value scaled to unit notional.
   *
   * @param tranche  the tranche product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date for discounting
   * @param priceType  clean or dirty price
   * @param refData  the reference data
   * @return the price
   */
  public double price(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    if (!tranche.getProtectionEndDate().isAfter(ratesProvider.getValuationDate())) {
      return 0d;
    }
    ResolvedCds cds = tranche.toResolvedCdsIndex().toSingleNameCds();
    double indexPrice = underlyingPricer.price(cds, ratesProvider, referenceDate, priceType, refData);
    // Scale by tranche width
    return tranche.getTrancheWidth() * indexPrice;
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value of the tranche product.
   * <p>
   * The present value is based on {@code referenceDate}, which is typically the valuation date
   * or cash settlement date if the product is associated with a Trade.
   * <p>
   * The tranche protection leg pays (1 - recoveryRate) for losses within the tranche range.
   * The premium leg pays the fixed coupon on the surviving tranche notional.
   *
   * @param tranche  the tranche product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date for discounting
   * @param priceType  clean or dirty price
   * @param refData  the reference data
   * @return the present value
   */
  public CurrencyAmount presentValue(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      PriceType priceType,
      ReferenceData refData) {

    if (!tranche.getProtectionEndDate().isAfter(ratesProvider.getValuationDate())) {
      return CurrencyAmount.of(tranche.getCurrency(), 0d);
    }
    // Use the CDS index as the underlying pricing instrument
    ResolvedCds cds = tranche.toResolvedCdsIndex().toSingleNameCds();
    // Compute the underlying CDS present value (without notional and buy/sell scaling)
    double indexPrice = underlyingPricer.price(cds, ratesProvider, referenceDate, priceType, refData);
    // Scale by tranche width and apply notional and buy/sell direction
    double trancheWidth = tranche.getTrancheWidth();
    double signedNotional = tranche.getBuySell().normalize(tranche.getNotional());
    double amount = signedNotional * trancheWidth * indexPrice;
    return CurrencyAmount.of(tranche.getCurrency(), amount);
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the present value sensitivity of the tranche product.
   * <p>
   * The sensitivity is computed from the underlying CDS price sensitivity,
   * scaled by the tranche width and notional.
   *
   * @param tranche  the tranche product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date for discounting
   * @param refData  the reference data
   * @return the present value sensitivity
   */
  public PointSensitivityBuilder presentValueSensitivity(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      ReferenceData refData) {

    if (!tranche.getProtectionEndDate().isAfter(ratesProvider.getValuationDate())) {
      return PointSensitivityBuilder.none();
    }
    ResolvedCds cds = tranche.toResolvedCdsIndex().toSingleNameCds();
    double signedNotional = tranche.getBuySell().normalize(tranche.getNotional());
    double trancheWidth = tranche.getTrancheWidth();
    return underlyingPricer.presentValueSensitivity(cds, ratesProvider, referenceDate, refData)
        .multipliedBy(trancheWidth / tranche.getNotional() * signedNotional);
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the par spread of the tranche product.
   * <p>
   * The par spread is the coupon rate such that the clean PV is zero.
   *
   * @param tranche  the tranche product
   * @param ratesProvider  the rates provider
   * @param referenceDate  the reference date for discounting
   * @param refData  the reference data
   * @return the par spread
   */
  public double parSpread(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider,
      LocalDate referenceDate,
      ReferenceData refData) {

    ArgChecker.isTrue(tranche.getProtectionEndDate().isAfter(ratesProvider.getValuationDate()),
        "CDS tranche already expired");
    ResolvedCds cds = tranche.toResolvedCdsIndex().toSingleNameCds();
    // The par spread is independent of the tranche width scaling
    return underlyingPricer.parSpread(cds, ratesProvider, referenceDate, refData);
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates the expected loss of the tranche.
   * <p>
   * The expected loss represents the expected credit loss absorbed by this tranche,
   * computed as the tranche's share of the expected portfolio loss.
   * <p>
   * Under a simplified homogeneous pool assumption, the expected loss for the tranche
   * is computed from the underlying index expected loss probability, scaled to the
   * tranche notional by the tranche width factor.
   *
   * @param tranche  the tranche product
   * @param ratesProvider  the rates provider
   * @return the expected loss as a currency amount
   */
  public CurrencyAmount expectedLoss(
      ResolvedCdsTranche tranche,
      CreditRatesProvider ratesProvider) {

    // Get the index survival probability at the protection end date
    LegalEntitySurvivalProbabilities survivalProbabilities =
        ratesProvider.survivalProbabilities(tranche.getCdsIndexId(), tranche.getCurrency());
    LocalDate protectionEndDate = tranche.getProtectionEndDate();
    double survivalProb = survivalProbabilities.survivalProbability(protectionEndDate);

    // Simplified expected loss: (1 - survivalProb) scaled by tranche width and notional
    RecoveryRates recoveryRates = ratesProvider.recoveryRates(tranche.getCdsIndexId());
    double recoveryRate = recoveryRates.recoveryRate(protectionEndDate);
    double trancheWidth = tranche.getTrancheWidth();

    // Expected loss for the tranche under homogeneous pool assumption
    // EL_tranche = (1 - RR) * (1 - SP) * trancheWidth * notional
    double expectedLossAmount = (1d - recoveryRate) * (1d - survivalProb) * trancheWidth * tranche.getNotional();
    return CurrencyAmount.of(tranche.getCurrency(), expectedLossAmount);
  }

}

