nsitivities parameterSensitivity = ratesProvider.parameterSensitivity(pointSensitivity);\n311:     CurrencyParameterSensitivities quoteSensitivity = MARKET_QUOTE_SENS.sensitivity(parameterSensitivity, ratesProvider);\n312:     return quoteSensitivity.total().multipliedBy(ONE_BASIS_POINT);\n313:   }\n314: \n315:   //-------------------------------------------------------------------------\n316:   // calculates market quote bucketed PV01 for all scenarios\n317:   ScenarioArray\u003cCurrencyParameterSensitivities\u003e pv01MarketQuoteBucketed(\n318:       ResolvedCdsIndexTrade trade,\n319:       CreditRatesScenarioMarketData marketData,\n320:       ReferenceData refData) {\n321: \n322:     return ScenarioArray.of(\n323:         marketData.getScenarioCount(),\n324:         i -\u003e pv01MarketQuoteBucketed(trade, marketData.scenario(i).creditRatesProvider(), refData));\n325:   }\n326: \n327:   // calculates market quote bucketed PV01 for one scenario\n328:   CurrencyParameterSensitivities pv01MarketQuoteBucketed(\n329:       ResolvedCdsIndexTrade trade,\n330:       CreditRatesProvider ratesProvider,\n331:       ReferenceData refData) {\n332: \n333:     PointSensitivities pointSensitivity = tradePricer.presentValueSensitivity(trade, ratesProvider, refData);\n334:     CurrencyParameterSensitivities parameterSensitivity = ratesProvider.parameterSensitivity(pointSensitivity);\n335:     return MARKET_QUOTE_SENS.sensitivity(parameterSensitivity, ratesProvider).multipliedBy(ONE_BASIS_POINT);\n336:   }\n337: \n338:   //-------------------------------------------------------------------------\n339:   // calculates parallel CS01 for all scenarios\n340:   CurrencyScenarioArray cs01Parallel(\n341: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/Strata--66225ca9@9d9ab49ce264443ddb305a8b1df6f48d01a2c67c/-/blob/modules/measure/src/main/java/com/opengamma/strata/measure/credit/CdsIndexMeasureCalculations.java%3FL270-340"}", "annotations": null, "meta": null}], "structu